package arch.day6;

/**
 * Day 6 advanced: Fibonacci trace, iterative alternative sketch, stack-depth decision table.
 */
public class Day6Advanced {

    static int fibNaive(int n) {
        if (n == 0) {
            return 0;
        }
        if (n == 1) {
            return 1;
        }
        return fibNaive(n - 1) + fibNaive(n - 2);
    }

    static int fibIter(int n) {
        if (n <= 1) {
            return n;
        }
        int a = 0;
        int b = 1;
        for (int i = 2; i <= n; i++) {
            int c = a + b;
            a = b;
            b = c;
        }
        return b;
    }

    static void spacer() {
        System.out.println("---");
    }

    static void block1() {
        System.out.println("=== Block 1: first 10 Fibonacci (naive) ===");
        System.out.println("note: teaching only — exponential recomputation");
        for (int i = 0; i < 10; i++) {
            System.out.print(fibNaive(i));
            if (i < 9) {
                System.out.print(' ');
            }
        }
        System.out.println();
        System.out.println("peek: fibNaive(10) would already fan out heavily");
        System.out.println();
    }

    static void block2() {
        System.out.println("=== Block 2: iterative matches for n=9 ===");
        System.out.println("naive fib(9)=" + fibNaive(9));
        System.out.println("iter fib(9)=" + fibIter(9));
        System.out.println("parity check n=6: naive=" + fibNaive(6) + " iter=" + fibIter(6));
        System.out.println();
    }

    static void block3() {
        System.out.println("=== Block 3: depth triage ===");
        System.out.println("risk signal              | response");
        System.out.println("-------------------------|-----------------------------");
        System.out.println("StackOverflowError spikes| cap depth, iterate, explicit stack");
        System.out.println("Exponential runtime      | memoise or loop");
        System.out.println("Wrong overload           | cast args, rename method");
        System.out.println("Primitive unchanged      | remember pass-by-value");
        System.out.println("Instance vs static call    | no this in static");
        System.out.println("Varargs ambiguity        | cast or rename overload");
        System.out.println("Mutual recursion cycles  | prove token consumption");
        System.out.println("Profiler hot tiny methods| trust JIT, avoid mega methods");
        System.out.println("review complete");
    }

    public static void main(String[] args) {
        System.out.println("banner: Day6 advanced recursion lab");
        block1();
        spacer();
        block2();
        spacer();
        block3();
        System.out.println("postscript: compare stack depth with -Xss experiments in lab only");
        System.out.println("postscript: pair recursion lessons with explicit stack iterators next week");
    }
}

