package arch.day6;

/**
 * Day 6 exercise — ties to assignments_phase1.json Day 6.
 * Naive fib is exponential time; iterative fib is O(n) for production n.
 */
public class Day6Exercise {

    static void explainPassByValue() {
        System.out.println("1) Primitives copy their bit pattern into the callee");
        System.out.println("2) Reference variables copy a pointer; both point at same object");
        System.out.println("3) Reassigning the callee parameter does not rewire caller vars");
        System.out.println("4) Mutating fields through the copied reference affects shared state");
    }

    static int add(int a, int b) {
        return a + b;
    }

    static double add(double a, double b) {
        return a + b;
    }

    static long factorial(int n) {
        if (n <= 1) {
            return 1;
        }
        return n * factorial(n - 1);
    }

    static int fibonacci(int n) {
        if (n == 0) {
            return 0;
        }
        if (n == 1) {
            return 1;
        }
        return fibonacci(n - 1) + fibonacci(n - 2);
    }

    public static void main(String[] args) {
        explainPassByValue();
        System.out.println("add int -> " + add(1, 2));
        System.out.println("add double -> " + add(1.0, 2.0));
        System.out.println("factorial(5)=" + factorial(5));
        StringBuilder sb = new StringBuilder();
        sb.append("First 10 Fibonacci: ");
        for (int i = 0; i < 10; i++) {
            sb.append(fibonacci(i));
            if (i < 9) {
                sb.append(' ');
            }
        }
        System.out.println(sb.toString());
    }
}

